pragma solidity ^0.8.4;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract MyToken is ERC20, Ownable, ReentrancyGuard {
    using SafeMath for uint256;

    uint256 public _taxFee;
    uint256 public _devFee;
    address public _liquidityWallet;
    bool private _paused;
    bool private _tradingEnabled;

    event Paused();
    event Unpaused();
    event OpenedTrading();
    event LiquidityAdded(address indexed account, uint256 amount);

    constructor() ERC20("Token", "TKN") {
        _mint(msg.sender, 1000000 * (10 ** uint256(decimals));
        _paused = true;
        _tradingEnabled = false;
        _owner = msg.sender;
    }

    modifier notPaused() {
        require(!_paused, "Contract is paused");
        _;
    }

    modifier onlyWhenTradingEnabled() {
        require(_tradingEnabled, "Trading is not enabled");
        _;
    }

    function pause() external onlyOwner {
        _paused = true;
        emit Paused();
    }

    function unpause() external onlyOwner {
        _paused = false;
        emit Unpaused();
    }

    function openTrading(uint256 taxFee, uint256 devFee, address liquidityWallet) external onlyOwner {
        require(!_tradingEnabled, "Trading is already enabled");
        _taxFee = taxFee;
        _devFee = devFee;
        _liquidityWallet = liquidityWallet;
        _tradingEnabled = true;
        emit OpenedTrading();
    }

    function _transfer(address sender, address recipient, uint256 amount) internal virtual override notPaused onlyWhenTradingEnabled {
        require(sender != address(0), "ERC20: transfer from the zero address");
